{
  "module_name": "vpc-network",
  "test_layers": {
    "unit": [
      "terraform fmt -check",
      "terraform validate",
      "tflint"
    ],
    "component": [
      "terraform plan -out plan.bin",
      "json-assert: resource_count==12"
    ],
    "integration": [
      "terratest examples/simple",
      "terratest examples/multi-region"
    ]
  },
  "policy_gates": [
    {
      "engine": "opa",
      "policies": [
        "no-public-buckets",
        "cmek-required",
        "no-primitive-roles"
      ]
    }
  ],
  "owner": {
    "name": "Olha Petrenko",
    "role": "platform lead"
  },
  "produced_at": "2026-05-23T10:00:00Z"
}
